VALUES
  ('pukao-d0d1b9a2-moex-00214', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '甲公司8月份無期初存貨。其直接材料、直接人工與製造費用資料如下： 在製品 製成品 銷貨成本 合計 直接材料 $1,700 $10,000 $26,200 $37,930 直接人工 2,250 16,000 42,920 60,170 已分攤製造費用 1,860 8,060 21,080 31,000 合計 $5,840 $34,060 $89,200 $129,100', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "e4cd6100a25c", "answer_pdf_sha1": "65c335a2499f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00215', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '月份製造費用少分攤$2,000。該公司依在製品、製成品與銷貨成本月底已分攤製造費用帳戶餘 額，處理多分攤或少分攤製造費用。 8月份處理多分攤或少分攤製造費用之日記簿分錄應包括下列何者？', '["借記銷貨成本$89,200", "貸記銷貨成本$1,360", "借記銷貨成本$1,360", "貸記銷貨成本$89,200"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "e4cd6100a25c", "answer_pdf_sha1": "65c335a2499f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00216', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '甲公司本期開始製造產品1,000單位， 完工900單位，期末在製品100單位，材料及加工成本之 完工程度分別為60%及30%，則材料之約當產量為何？', '["900單位", "930單位", "960單位", "1,000單位"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "e4cd6100a25c", "answer_pdf_sha1": "65c335a2499f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00217', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '辛公司採用作業基礎成本制度，以下是該公司的作業活動相關資訊： 作業活動 成本 成本動因 帳戶諮詢 $240,000 20,000小時數 開立發票 $700,000 7,000,000開立文字行數 帳戶驗證 $98,000 50,000帳戶數 文件準備 $32,000 4,000文件份數 總成本 $1,070,000 該公司所屬之甲部門與乙部門所使用的各項作業活動資訊如下： 甲部門 乙部門 帳戶諮詢之時數 2,000小時數 3,800小時數 開立發票之文字行數 550,000行數 450,000行數 帳戶驗證之帳戶數 8,000帳戶數 6,000帳戶數 文件準備之文件份數 1,500文件份數 1,200文件份數 該公司應分攤多少成本至甲部門？', '["$98,825", "$106,680", "$120,000", "$130,075"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "e4cd6100a25c", "answer_pdf_sha1": "65c335a2499f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00218', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '丙公司銷售某產品，單位售價$100，單位變動成本$60，每年銷售量為 10,000 單位，固定成本為 $300,000。丙公司正考慮增加$85,000廣告費來促銷產品，預期可使銷售量每年增加10%，但增加 廣告費並不影響產品的單位售價及單位變動成本。下列敘述何者錯誤？', '["在不考慮增加廣告費下，丙公司的損益兩平點銷售量為7,500單位", "在不考慮增加廣告費下，丙公司的營業槓桿度為4", "在增加廣告費情況下，丙公司的營業槓桿度為8", "在追求利潤極大化目標下，丙公司應該增加廣告費"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "e4cd6100a25c", "answer_pdf_sha1": "65c335a2499f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00219', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '甲公司進行管理決策，在A方案與B方案之間擇一執行。有關機會成本之敘述，下列何者正確？', '["產能限制愈多則機會成本愈大", "機會成本愈大代表現金支出愈多", "二方案之機會成本需認列在損益表", "A方案之現金收入為B方案之總機會成本"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "e4cd6100a25c", "answer_pdf_sha1": "65c335a2499f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00220', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '甲公司今年製造成本總額資料如下：直接原料$100,000、直接人工$200,000以及製造費用$80,000， 去年底期末製成品存貨$11,400，今年的銷貨成本總數為$380,000，今年底期末製成品存貨是多 少？', '["$11,400", "$12,000", "$13,400", "$14,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "e4cd6100a25c", "answer_pdf_sha1": "65c335a2499f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00221', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '小強於樂透夜市擺攤販售自動鉛筆及筆心，每個月必須固定付給夜市管委會$4,500的場地租借費 用，依據小強的經驗，每位顧客平均購買一支自動鉛筆會搭配購買兩盒筆心，販售一支自動鉛筆 及一盒筆心的邊際貢獻分別為$100 及$25，小強每個月擺攤若要不賺也不賠，要販售幾支自動鉛 筆及幾盒筆心？', '["20支自動鉛筆及40盒筆心", "25支自動鉛筆及50盒筆心", "30支自動鉛筆及60盒筆心", "35支自動鉛筆及70盒筆心"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "e4cd6100a25c", "answer_pdf_sha1": "65c335a2499f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00222', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '甲公司預計明年前4個月銷售額資訊如下： 月份 預計銷售額 1月 $156,000 2月 140,400 3月 171,600 4月 187,200 該公司毛利率為40%，今年12月底的存貨為$28,080。此外，每個月底的目標存貨為下個月銷貨 成本的30%。二月份預計進貨總額為何？', '["$78,624", "$84,240", "$89,856", "$149,760"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "e4cd6100a25c", "answer_pdf_sha1": "65c335a2499f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00223', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '甲公司估計生產檯燈的單位成本是$1,900，其中包括80%的變動成本和20%的固定成本，該公司 有閒置產能。乙公司的訂價政策是按全部成本加成45%。甲公司被邀請參加乙公司一次性特殊訂 單的競標，以提供180座檯燈。甲公司應該在這個特殊訂單上出的最低價格是多少？', '["$273,600", "$342,000", "$396,720", "$495,900"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "e4cd6100a25c", "answer_pdf_sha1": "65c335a2499f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL)
